.motoplus-admin-grid{display:grid;grid-template-columns:repeat(3,minmax(180px,1fr));gap:14px 18px;max-width:1100px}.motoplus-field label{display:block;font-weight:700;margin-bottom:6px}.motoplus-field input,.motoplus-field select,.motoplus-field textarea{width:100%;max-width:100%;border-radius:8px;border:1px solid #d0d5dd;padding:8px 10px}.motoplus-check{font-weight:400!important}.motoplus-lookup-row{display:flex;align-items:flex-end;gap:12px;background:#f8fafc;border:1px solid #e5e7eb;border-radius:14px;padding:16px;margin:12px 0 18px;max-width:900px}.motoplus-lookup-row label{display:block;font-weight:700;margin-bottom:6px}.motoplus-lookup-row input{min-width:240px;text-transform:uppercase}.motoplus-gallery-preview{display:flex;flex-wrap:wrap;gap:6px}.motoplus-gallery-preview img{width:72px;height:72px;object-fit:cover;border-radius:8px;border:1px solid #ddd}.motoplus-ai-box{background:#fff;border:1px solid #e5e7eb;border-radius:14px;padding:16px;max-width:900px;margin-top:16px}.motoplus-stats{display:grid;grid-template-columns:repeat(4,minmax(140px,1fr));gap:16px;margin:20px 0}.motoplus-stats div{background:#fff;border:1px solid #e5e7eb;border-radius:16px;padding:20px}.motoplus-stats strong{display:block;font-size:34px}.motoplus-stats span{color:#667085}.column-image img{width:70px;height:50px;object-fit:cover;border-radius:6px}@media(max-width:900px){.motoplus-admin-grid{grid-template-columns:1fr}.motoplus-lookup-row{display:block}.motoplus-stats{grid-template-columns:1fr 1fr}}
.motoplus-import-box{background:#fff;border:1px solid #d0d5dd;border-radius:14px;padding:18px;max-width:900px;margin-top:18px}.motoplus-import-box input{margin-top:8px}.motoplus-import-box .button{margin-top:8px}#motoplus_import_result{font-weight:600;margin-left:8px}#motoplus_import_preview{max-width:900px;margin-top:16px}
